generated_oml:
// C3: Physical sensing components
instance SwingAngleEncoder : DTDFVocab:SensingComponent [
    base:desc "Swing-angle encoder measuring the crane swing angle"
    DTDFVocab:producedData SwingAngleDataTransmitted
]

instance Anemometer : DTDFVocab:SensingComponent [
    base:desc "Anemometer measuring ambient wind speed for the crane"
    DTDFVocab:producedData WindSpeedDataTransmitted
]

instance ArduinoMotorStatusSensor : DTDFVocab:SensingComponent [
    base:desc "Arduino board providing motor status feedback (current, speed, error flags)"
    DTDFVocab:producedData MotorStatusDataTransmitted
]

// C2: Acting components
instance CartStepperMotor : DTDFVocab:ActingComponent [
    base:desc "Stepper motor driving the cart movement, controlled via TMC4671‑Eval"
]

instance HoistStepperMotor : DTDFVocab:ActingComponent [
    base:desc "Stepper motor driving the hoist, controlled via TMC4671‑Eval"
]

instance Electromagnet : DTDFVocab:ActingComponent [
    base:desc "Electromagnet at the end of the hoist for load attachment/release"
]

// C4: Physical‑to‑virtual interaction (sensor data transmission)
instance SwingAngleDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SwingAngleEncoder
]

instance WindSpeedDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom Anemometer
]

instance MotorStatusDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom ArduinoMotorStatusSensor
]

// C10: Data produced from sensors
instance SwingAngleTimeSeries : DTDFVocab:Data [
    base:desc "Logged time‑series of swing‑angle measurements stored in TimescaleDB"
    DTDFVocab:fromData SwingAngleDataTransmitted
    DTDFVocab:inputTo TimescaleDatabaseEnabler, GrafanaDashboardEnabler
]

instance WindSpeedTimeSeries : DTDFVocab:Data [
    base:desc "Logged time‑series of wind‑speed measurements stored in TimescaleDB"
    DTDFVocab:fromData WindSpeedDataTransmitted
    DTDFVocab:inputTo TimescaleDatabaseEnabler, GrafanaDashboardEnabler
]

instance MotorStatusTimeSeries : DTDFVocab:Data [
    base:desc "Logged time‑series of motor status (speed, current, errors) stored in TimescaleDB"
    DTDFVocab:fromData MotorStatusDataTransmitted
    DTDFVocab:inputTo TimescaleDatabaseEnabler, GrafanaDashboardEnabler
]

// C3: Virtual sensing components (model‑generated data)
instance TrajectoryGenerationComponent : DTDFVocab:SensingComponent [
    base:desc "Component that produces optimal trajectory data for the crane"
    DTDFVocab:producedData TrajectoryDataTransmitted
]

instance TrajectoryDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom TrajectoryGenerationComponent
]

instance GeneratedTrajectoryData : DTDFVocab:Data [
    base:desc "Trajectory data generated by the Trajectory Generation Service"
    DTDFVocab:fromData TrajectoryDataTransmitted
    DTDFVocab:inputTo SimulationEnabler
]

instance ValidationMetricsComponent : DTDFVocab:SensingComponent [
    base:desc "Component that produces validation metrics comparing measured and simulated trajectories"
    DTDFVocab:producedData ValidationMetricsDataTransmitted
]

instance ValidationMetricsDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom ValidationMetricsComponent
]

instance ValidationMetricsData : DTDFVocab:Data [
    base:desc "Validation metrics (error, confidence bounds) produced by the Continuous Validation Service"
    DTDFVocab:fromData ValidationMetricsDataTransmitted
    DTDFVocab:inputTo ContinuousValidationEnabler
]

// C10: Models
instance CadGeometryModel : DTDFVocab:Model [
    base:desc "CAD geometry model of the gantry crane (Fusion 360 files)"
    DTDFVocab:inputTo SimulationEnabler
]

instance KinematicModel : DTDFVocab:Model [
    base:desc "Kinematic model used by the Trajectory Generator to compute feasible motions"
    DTDFVocab:inputTo TrajectoryGeneratorEnabler
]

instance DynamicSimulationModel : DTDFVocab:Model [
    base:desc "Dynamic physics simulation model used by the Simulation Service"
    DTDFVocab:inputTo SimulationEnabler
]

instance ValidationModel : DTDFVocab:Model [
    base:desc "Validation model used by the Continuous Validation Service for trajectory comparison"
    DTDFVocab:inputTo ContinuousValidationEnabler
]

instance HarborLevelModel : DTDFVocab:Model [
    base:desc "Harbor‑level model extending the crane context (e.g., dock geometry)"
    DTDFVocab:inputTo SimulationEnabler
]

instance ShipBuoyancyModel : DTDFVocab:Model [
    base:desc "Ship buoyancy model used in integrated simulations with the crane"
    DTDFVocab:inputTo SimulationEnabler
]

// C11: Enablers
instance TimescaleDatabaseEnabler : DTDFVocab:Enabler [
    base:desc "TimescaleDB container persisting time‑series sensor data"
    DTDFVocab:enables DataLoggingService
]

instance GrafanaDashboardEnabler : DTDFVocab:Enabler [
    base:desc "Grafana container visualizing data from TimescaleDB"
    DTDFVocab:enables VisualizationService
]

instance MqttBrokerEnabler : DTDFVocab:Enabler [
    base:desc "Eclipse Mosquitto MQTT broker for event distribution"
    DTDFVocab:enables ContinuousValidationService, HumanMachineInterfaceService
]

instance TrajectoryGeneratorEnabler : DTDFVocab:Enabler [
    base:desc "Docker container hosting the Trajectory Generation Service"
    DTDFVocab:enables TrajectoryGenerationService
]

instance SimulationEnabler : DTDFVocab:Enabler [
    base:desc "Docker container running the Physics Simulation Service"
    DTDFVocab:enables PhysicsSimulationService
]

instance ContinuousValidationEnabler : DTDFVocab:Enabler [
    base:desc "Docker container executing the Continuous Validation Service"
    DTDFVocab:enables ContinuousValidationService
]

instance HumanMachineInterfaceEnabler : DTDFVocab:Enabler [
    base:desc "Python‑based Human‑Machine Interface container"
    DTDFVocab:enables HumanMachineInterfaceService
]

instance PhysicalCraneInterfaceEnabler : DTDFVocab:Enabler [
    base:desc "Python Physical Crane Interface translating Arduino data to MQTT/TimescaleDB"
    DTDFVocab:enables DataLoggingService
]

// C6: Services
instance DataLoggingService : DTDFVocab:Service [
    base:desc "Continuous data logging service streaming sensor data into TimescaleDB"
    DTDFVocab:provides DataLoggingInsight
]

instance VisualizationService : DTDFVocab:Service [
    base:desc "Grafana visualization service presenting trajectory plots and confidence bounds"
    DTDFVocab:provides TrajectoryPlotInsight
]

instance TrajectoryGenerationService : DTDFVocab:Service [
    base:desc "Service that computes optimal crane trajectories based on kinematic constraints"
]

instance PhysicsSimulationService : DTDFVocab:Service [
    base:desc "Physics‑based simulation service evaluating crane dynamics using CAD and dynamic models"
]

instance ContinuousValidationService : DTDFVocab:Service [
    base:desc "Service that continuously validates measured trajectories against simulated ones and raises alerts"
    DTDFVocab:provides ValidationAlertInsight
]

instance HumanMachineInterfaceService : DTDFVocab:Service [
    base:desc "Python‑based HMI allowing operators to view insights and trigger actions"
    DTDFVocab:provides PauseCraneAction, ReplanTrajectoryAction, AdjustControllerParametersAction
]

// C17: Insights
instance DataLoggingInsight : DTDFVocab:Insight [
    base:desc "Logged measurement data are available for downstream analysis and visualization"
]

instance TrajectoryPlotInsight : DTDFVocab:Insight [
    base:desc "Trajectory plots with confidence bounds displayed on the Grafana dashboard"
]

instance ValidationAlertInsight : DTDFVocab:Insight [
    base:desc "Automatic alert generated when validation thresholds are exceeded"
]

// C17: Actions
instance PauseCraneAction : DTDFVocab:Action [
    base:desc "Operator command to pause crane motion"
    DTDFVocab:IsAutomatic false
]

instance ReplanTrajectoryAction : DTDFVocab:Action [
    base:desc "Operator command to request a new optimal trajectory"
    DTDFVocab:IsAutomatic false
]

instance AdjustControllerParametersAction : DTDFVocab:Action [
    base:desc "Operator command to adjust controller PID parameters"
    DTDFVocab:IsAutomatic false
]

// C1: Physical components (non‑sensing)
instance CraneFrame : DTDFVocab:Component [
    base:desc "Steel frame of the laboratory‑scale gantry crane"
]

instance PowerSupplyUnit : DTDFVocab:Component [
    base:desc "Power supply unit providing voltage/current to motors and electronics"
]

// C8: Environment
instance GantryCraneEnvironment : DTDFVocab:Environment [
    base:contains CartStepperMotor, HoistStepperMotor, Electromagnet,
                  SwingAngleEncoder, Anemometer, ArduinoMotorStatusSensor,
                  CraneFrame, PowerSupplyUnit
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "Control commands generated by the Control Application, Trajectory Generator Service, or the Human‑Machine Interface are transmitted through the Physical Crane Interface to the motor controllers and electromagnet, effecting movements, homing, zeroing and container pick‑up."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "The architecture consists of the physical crane connected to a PC via the Arduino interface; on the PC run Docker‑containerized services (DB, MQTT, Dashboard) and Python applications (Control, Logging, HMI) that communicate through MQTT and direct API calls, forming an integrated digital twin orchestrated by Docker‑Compose."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "The twin covers the design stage (CAD models of the crane in Autodesk Fusion 360), the manufacturing stage (physical crane built from the bill‑of‑materials), and the operational stage (real‑time sensor data, simulated models and validation)."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Continuous Validation Service continuously compares executed trajectories with simulated ones, computes distance metrics, checks against a predefined threshold and raises alerts on the dashboard when the fidelity drops below the acceptable level."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Communication between PT and DT uses a Python interface over a serial/USB link to the Arduino, and inter‑service messaging uses MQTT (Eclipse Mosquitto) over TCP/IP; the database is accessed via standard PostgreSQL/TimescaleDB SQL connections."
]

instance dt_hosting_deployment : DTDFVocab:Deployment [
    base:desc "All components run on a single personal computer; Docker containers host the database, MQTT broker and Grafana dashboard, while the Python modules run as processes; Docker‑Compose automates startup and network configuration."
]
